mapper.update:
update punch_record
set user_id = #{userId}, check_in_time = #{checkInTime}, check_in_type = #{checkInType}, 
    check_in_status = #{checkInStatus}, check_in_location = #{checkInLocation}, update_time = #{updateTime}
where id = #{id}

mapper.select:
select
    id, user_id, check_in_time, check_in_type, check_in_status, check_in_location, create_time, update_time
from punch_record
where user_id = #{userId}
order by create_time desc
limit #{limit} offset #{offset}
